static void GetFixedTree(unsigned *ll_lengths, unsigned *d_lengths)
/* The fixed Huffman tree of DEFLATE: code lengths are written for all
   ZOPFLI_NUM_LL literal/length codes and all ZOPFLI_NUM_D distance codes. */
