void ZopfliLengthsToSymbols(const unsigned *lengths, size_t n, unsigned maxbits,
                            unsigned *symbols)
/* Code lengths fit in the DEFLATE limit, keeping (maxbits + 1) malloc sizes and
   table indices in range. */
