cat > /tmp/mini.c <<'EOF'
#include <stddef.h>
void f(unsigned char *bp, unsigned char **out, size_t *outsize)
__CPROVER_requires(__CPROVER_is_fresh(bp, sizeof(*bp)))
__CPROVER_requires(__CPROVER_is_fresh(outsize, sizeof(*outsize)))
__CPROVER_requires(__CPROVER_is_fresh(out, sizeof(*out)))
__CPROVER_requires(*bp <= 7)
__CPROVER_requires(((*outsize) & ((*outsize) - 1)) != 0)
__CPROVER_requires(__CPROVER_is_fresh(*out, (*outsize) + 1))
__CPROVER_assigns(*bp, *outsize, __CPROVER_object_whole(*out))
__CPROVER_ensures(*bp == 99)
{
  (*out)[0] = 1;
  *bp = (*bp + 1) & 7;
  *outsize = *outsize + 1;
}
EOF
cd /tmp; rm -f mini.goto cmini.goto; goto-cc -o mini.goto --function f mini.c 2>&1 | tail -2; \
goto-instrument --enforce-contract f mini.goto cmini.goto 2>&1 | tail -2; \
cbmc cmini.goto --function f 2>&1 | grep -iE "postcondition|VERIFICATION|^\*\* [0-9]"

